import{_ as e,o as n,c as s,a2 as o}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Modelado estrategico","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/08-modelado-estrategico.md","filePath":"full-stack/arquitectura/ddd/08-modelado-estrategico.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/ddd/08-modelado-estrategico.md"};function t(l,a,r,c,d,p){return n(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="modelado-estrategico" tabindex="-1">Modelado estrategico <a class="header-anchor" href="#modelado-estrategico" aria-label="Permalink to &quot;Modelado estrategico&quot;">​</a></h1><p>El modelado estrategico ayuda a decidir donde invertir esfuerzo y como dividir un sistema grande.</p><h2 id="subdominios" tabindex="-1">Subdominios <a class="header-anchor" href="#subdominios" aria-label="Permalink to &quot;Subdominios&quot;">​</a></h2><p>No todas las partes de un sistema tienen la misma importancia.</p><ul><li>Core domain: lo que diferencia el negocio.</li><li>Supporting domain: necesario, pero no diferencial.</li><li>Generic domain: comun en muchas empresas.</li></ul><h2 id="ejemplo" tabindex="-1">Ejemplo <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo&quot;">​</a></h2><p>En una plataforma educativa:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Core domain:</span></span>
<span class="line"><span>  aprendizaje adaptativo</span></span>
<span class="line"><span>  evaluacion personalizada</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Supporting domain:</span></span>
<span class="line"><span>  catalogo de cursos</span></span>
<span class="line"><span>  mensajeria</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Generic domain:</span></span>
<span class="line"><span>  autenticacion</span></span>
<span class="line"><span>  facturacion basica</span></span></code></pre></div><h2 id="invertir-donde-importa" tabindex="-1">Invertir donde importa <a class="header-anchor" href="#invertir-donde-importa" aria-label="Permalink to &quot;Invertir donde importa&quot;">​</a></h2><p>El core domain merece mas modelado, pruebas y conversaciones. Un dominio generico puede resolverse con herramientas existentes.</p><h2 id="context-mapping" tabindex="-1">Context mapping <a class="header-anchor" href="#context-mapping" aria-label="Permalink to &quot;Context mapping&quot;">​</a></h2><p>Un context map muestra relaciones entre contextos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Catalog --customer/supplier--&gt; Learning</span></span>
<span class="line"><span>Learning --event--&gt; Billing</span></span>
<span class="line"><span>Identity --shared kernel--&gt; All</span></span></code></pre></div><h2 id="relaciones-comunes" tabindex="-1">Relaciones comunes <a class="header-anchor" href="#relaciones-comunes" aria-label="Permalink to &quot;Relaciones comunes&quot;">​</a></h2><ul><li>Customer/Supplier: un contexto consume el contrato de otro.</li><li>Conformist: un contexto acepta el modelo de otro.</li><li>Anti-corruption layer: un contexto traduce para protegerse.</li><li>Shared kernel: se comparte una parte pequena y gobernada.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>El core domain esta identificado.</li><li>No se sobredisena lo generico.</li><li>Los contextos estan mapeados.</li><li>Las relaciones tienen contratos claros.</li><li>Las decisiones reflejan valor de negocio, no solo comodidad tecnica.</li></ul>`,17)])])}const h=e(i,[["render",t]]);export{m as __pageData,h as default};
